class Solution:
    def makeSmallestPalindrome(self, s):
        arr = list(s)
        i, j = 0, len(arr) - 1
        while i < j:
            if arr[i] != arr[j]:
                c = min(arr[i], arr[j])
                arr[i] = c
                arr[j] = c
            i += 1
            j -= 1
        return ''.join(arr)

