var makeSmallestPalindrome = function(s) {
    const arr = s.split('');
    let i = 0, j = arr.length - 1;
    while (i < j) {
        if (arr[i] !== arr[j]) {
            const c = arr[i] < arr[j] ? arr[i] : arr[j];
            arr[i] = c;
            arr[j] = c;
        }
        i += 1;
        j -= 1;
    }
    return arr.join('');
};
